class Solution {
public:
    string minimizeStringValue(string s) {
        int n = s.size();
        vector<int> freq(26, 0);
        vector<int> qpos;

        // First pass: count fixed letters and collect '?' positions
        for (int i = 0; i < n; ++i) {
            if (s[i] != '?') {
                freq[s[i] - 'a']++;
            } else {
                qpos.push_back(i);
            }
        }

        // Determine optimal characters for '?'
        string opt;
        for (int i = 0; i < qpos.size(); ++i) {
            int minChar = 0;
            for (int c = 0; c < 26; ++c) {
                if (freq[c] < freq[minChar]) {
                    minChar = c;
                }
            }
            opt.push_back('a' + minChar);
            freq[minChar]++;
        }

        // Sort opt lexicographically for smallest string
        sort(opt.begin(), opt.end());

        // Replace '?' in original string
        int idx = 0;
        for (int pos : qpos) {
            s[pos] = opt[idx++];
        }

        return s;
    }
};
```
